const payload = $json.body ?? $json;
const headers = $json.headers ?? {};
const expectedToken = $env.ASAAS_WEBHOOK_TOKEN || '';
const receivedToken = headers['asaas-access-token'] || headers['Asaas-Access-Token'] || '';

if (expectedToken && receivedToken !== expectedToken) {
  throw new Error('Webhook Asaas sem token valido');
}

const payment = payload.payment || {};
const rawStatus = String(payment.status || payload.event || 'PENDING').toUpperCase();
let normalizedStatus = 'pending';

if (['PAYMENT_RECEIVED', 'PAYMENT_CONFIRMED', 'PAYMENT_CREATED'].includes(String(payload.event || '').toUpperCase())) {
  normalizedStatus = payload.event === 'PAYMENT_CREATED' ? 'pending' : 'confirmed';
}
if (['RECEIVED', 'CONFIRMED', 'RECEIVED_IN_CASH'].includes(rawStatus)) normalizedStatus = 'confirmed';
if (['OVERDUE', 'DELETED', 'CANCELLED', 'REFUNDED'].includes(rawStatus)) normalizedStatus = rawStatus === 'REFUNDED' ? 'refunded' : 'failed';

const paymentId = payment.id || payload.id || null;
if (!paymentId) {
  throw new Error('Webhook Asaas sem payment.id');
}

return [{
  json: {
    provider_payment_id: paymentId,
    external_reference: payment.externalReference || null,
    provider_customer_id: payment.customer || null,
    status: normalizedStatus,
    raw_status: rawStatus,
    billingType: payment.billingType || null,
    amount: payment.value || null,
    due_date: payment.dueDate || null,
    invoice_url: payment.invoiceUrl || null,
    bank_slip_url: payment.bankSlipUrl || null,
    payment_link: payment.invoiceUrl || payment.bankSlipUrl || null,
    status_detail: `Evento Asaas: ${payload.event || rawStatus}` ,
    webhook_payload: payload,
  },
}];
